"use client";

import { useEffect, useState } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";
import { useTypewriter } from "../hooks/useTypewriter";

const BOOT_LINES = [
  "PALE.SIGNAL BIOS v3.7 — cold boot 21:58:04 KST",
  "phosphor driver ............... OK",
  "memory 640K ................... OK (as it always was)",
  "azimuth drive DISH-01 ......... locked",
  "azimuth drive DISH-02 ......... locked",
  "azimuth drive DISH-03 ......... retired — skipped, with respect",
  "calibrating against the hum of the moon ... done",
  "channel open. 하늘이 호출을 수락했다.",
] as const;

const FULL_LOG = BOOT_LINES.join("\n");

/**
 * Section 01 — the boot hero. Server-rendered (and no-JS) state is the
 * *completed* boot screen; once JS mounts, the terminal goes dark and boots
 * for real. Any key, tap, wheel, or scroll completes it instantly, and a
 * hard timeout guarantees it can never trap anyone.
 */
export default function BootSequence() {
  const reduced = usePrefersReducedMotion();
  const [play, setPlay] = useState(false);
  const { settled, typing, done, finish } = useTypewriter(BOOT_LINES, play);

  useEffect(() => {
    if (reduced) {
      finish();
      return;
    }
    // A breath of black screen, then power on.
    const id = window.setTimeout(() => setPlay(true), 60);
    return () => window.clearTimeout(id);
  }, [reduced, finish]);

  const booting = play && !done;

  // Skip on any input. Never trap the user in a boot screen.
  useEffect(() => {
    if (!booting) return;
    const skip = () => finish();
    window.addEventListener("keydown", skip);
    window.addEventListener("pointerdown", skip);
    window.addEventListener("wheel", skip, { passive: true });
    window.addEventListener("touchstart", skip, { passive: true });
    window.addEventListener("scroll", skip, { passive: true });
    return () => {
      window.removeEventListener("keydown", skip);
      window.removeEventListener("pointerdown", skip);
      window.removeEventListener("wheel", skip);
      window.removeEventListener("touchstart", skip);
      window.removeEventListener("scroll", skip);
    };
  }, [booting, finish]);

  // Belt and suspenders: the boot always completes on its own.
  useEffect(() => {
    if (!booting) return;
    const t = window.setTimeout(finish, 7000);
    return () => window.clearTimeout(t);
  }, [booting, finish]);

  return (
    <header className="ps-hero" id="ps-boot">
      <div className="ps-hero__log" role="img" aria-label={FULL_LOG}>
        <pre aria-hidden="true" className="ps-hero__pre">
          {settled.join("\n")}
          {booting ? (
            <>
              {settled.length > 0 ? "\n" : ""}
              {typing}
              <span className="ps-cursor" />
            </>
          ) : null}
        </pre>
      </div>

      <div className={`ps-hero__id ${booting ? "is-waiting" : "is-on"}`}>
        <h1 className="ps-title" aria-label="PALE.SIGNAL">
          <span aria-hidden="true" className="ps-title__text">
            PALE.SIGNAL
          </span>
        </h1>
        <p className="ps-hero__sub">
          <span lang="ko">관측소</span> — listening post
          <span className="ps-cursor ps-cursor--idle" aria-hidden="true" />
        </p>
        <p className="ps-hero__meta">
          est. 1979 · decommissioned 2019 · still listening ·{" "}
          <span lang="ko">아직 듣고 있음</span>
        </p>
      </div>

      {booting ? (
        <p className="ps-hero__hint" aria-hidden="true">
          any key / tap — skip boot ·{" "}
          <span lang="ko">아무 키나 누르면 건너뜁니다</span>
        </p>
      ) : (
        <p className="ps-hero__hint" aria-hidden="true">
          ▼ scroll — <span lang="ko">오늘 밤의 기록으로</span>
        </p>
      )}
    </header>
  );
}

"use client";

import { useState } from "react";

type DishStatus = "tracking" | "holding" | "retired";

type Dish = {
  id: string;
  code: string;
  nameKo: string;
  nameEn: string;
  az: string;
  el: string;
  status: DishStatus;
  statusEn: string;
  statusKo: string;
  noteEn: string;
  noteKo: string;
};

const DISHES: Dish[] = [
  {
    id: "d1",
    code: "DISH-01",
    nameKo: "매화",
    nameEn: "MAEHWA",
    az: "214.7°",
    el: "41.2°",
    status: "tracking",
    statusEn: "TRACKING",
    statusKo: "추적 중",
    noteEn:
      "on the Crab pulsar. last night it counted 1,594,882 beats and dropped none.",
    noteKo:
      "게성운 펄서 담당. 어젯밤 1,594,882번의 박동을 세었고, 하나도 흘리지 않았다.",
  },
  {
    id: "d2",
    code: "DISH-02",
    nameKo: "동백",
    nameEn: "DONGBAEK",
    az: "097.3°",
    el: "12.8°",
    status: "holding",
    statusEn: "HOLDING",
    statusKo: "대기 중",
    noteEn:
      "the moon again. nothing new to say — we never stop listening anyway.",
    noteKo:
      "또 달이다. 새로 하는 말은 없지만, 그래도 듣는 일은 그만두지 않는다.",
  },
  {
    id: "d3",
    code: "DISH-03",
    nameKo: "수선",
    nameEn: "SUSEON",
    az: "000.0°",
    el: "90.0°",
    status: "retired",
    statusEn: "RETIRED",
    statusKo: "퇴역",
    noteEn:
      "retired 2019, still aimed at zenith. some habits outlive their duty.",
    noteKo:
      "2019년 퇴역, 지금도 천정을 향해 있다. 어떤 버릇은 소임보다 오래 산다.",
  },
];

/**
 * Section 04 — the three antennas as a monospace ledger. Each row is a real
 * <button> (keyboard-reachable, aria-expanded) that opens a one-line note.
 * Without JS the notes are simply visible — hiding is gated on `.ps-js`.
 */
export default function Dishes() {
  const [open, setOpen] = useState<string | null>(null);

  return (
    <section className="ps-dishes" aria-labelledby="ps-dishes-title">
      <div className="ps-sechead" data-reveal>
        <span className="ps-sechead__no" aria-hidden="true">
          04
        </span>
        <h2 className="ps-sechead__title" id="ps-dishes-title">
          the dishes{" "}
          <span lang="ko" className="ps-sechead__ko">
            세 개의 귀
          </span>
        </h2>
      </div>

      <ul className="ps-dishes__list">
        {DISHES.map((dish) => {
          const expanded = open === dish.id;
          return (
            <li
              key={dish.id}
              data-reveal
              className={`ps-dish ps-dish--${dish.status}`}
            >
              <button
                type="button"
                className="ps-dish__row"
                aria-expanded={expanded}
                aria-controls={`ps-dish-note-${dish.id}`}
                onClick={() => setOpen(expanded ? null : dish.id)}
              >
                <span className="ps-dish__cross" aria-hidden="true">
                  +
                </span>
                <span className="ps-dish__code">{dish.code}</span>
                <span className="ps-dish__name">
                  <span lang="ko">{dish.nameKo}</span> · {dish.nameEn}
                </span>
                <span className="ps-dish__az">AZ {dish.az}</span>
                <span className="ps-dish__el">EL {dish.el}</span>
                <span className="ps-dish__status">
                  {dish.statusEn} — <span lang="ko">{dish.statusKo}</span>
                </span>
              </button>
              <div
                id={`ps-dish-note-${dish.id}`}
                className={`ps-dish__note ${expanded ? "is-open" : "is-closed"}`}
              >
                <p>{dish.noteEn}</p>
                <p lang="ko">{dish.noteKo}</p>
              </div>
            </li>
          );
        })}
      </ul>
    </section>
  );
}

