.ps-root {
  /* -- palette ---------------------------------------------------------- */
  --ps-black: #0a0f0a;            /* tube black — the unlit screen */
  --ps-phosphor: #33ff66;         /* phosphor green — 14.5:1 on tube black */
  --ps-phosphor-dim: rgba(51, 255, 102, 0.72); /* ≈ #27b54a — 7.2:1, secondary text */
  --ps-dim-trace: #1d5c31;        /* decorative ONLY (2.4:1): rules, faint ASCII */
  --ps-amber: #ffb000;            /* alert — 10.6:1 */
  --ps-glare: #c8ffd9;            /* glass glare — low alpha washes + ASCII peaks */
  --ps-grid-line: rgba(29, 92, 49, 0.4);   /* derived from dim trace */
  --ps-scan-ink: rgba(3, 8, 4, 0.28);      /* derived: scanline ink */

  /* -- type -------------------------------------------------------------- */
  --ps-font-crt: var(--font-vt323), "VT323", "Courier New", monospace;
  --ps-font-ko: var(--font-nanum-coding), "Nanum Gothic Coding", monospace;
  /* Hangul falls through VT323 into Nanum Gothic Coding even without :lang */
  --ps-font-stack: var(--font-vt323), var(--font-nanum-coding), monospace;

  /* -- motion ------------------------------------------------------------ */
  --ps-ease-out: cubic-bezier(0.16, 1, 0.3, 1);   /* reveals: fast in, long tail */
  --ps-ease-crt: cubic-bezier(0.7, 0, 0.2, 1);    /* bloom: violent, then settles */
  --ps-reveal-ms: 600ms;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--ps-black);
  color: var(--ps-phosphor);
  font-family: var(--ps-font-stack);
  font-size: clamp(17px, 2.2vw + 10px, 21px);
  line-height: 1.5;
  overflow-x: hidden;
  overflow-x: clip;
}

