/* Rare one-frame horizontal jitter (~every 12.4s) and a glare breath.
   Jitter lives on the fixed viewport-sized glass, never on .ps-screen:
   an infinite animation on the full-height scroll wrapper promotes a
   page-sized compositor layer (jank + broken tab captures). */
.ps-js .ps-crt {
  animation: ps-jitter 12.4s linear infinite;
}

.ps-js .ps-crt__glare {
  animation: ps-flicker 9.4s linear infinite;
}

/* ==========================================================================
   Scroll reveals — JS-gated pre-state, transform/opacity only
   ========================================================================== */

.ps-js [data-reveal] {
  opacity: 0;
  transform: translateY(16px);
  transition:
    opacity var(--ps-reveal-ms) var(--ps-ease-out),
    transform var(--ps-reveal-ms) var(--ps-ease-out);
  will-change: opacity, transform;
}

.ps-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity / filter only
   ========================================================================== */

@keyframes ps-blink {
  0% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

@keyframes ps-appear {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

/* Phosphor bloom: overdrive, collapse, overshoot, settle */
@keyframes ps-bloom {
  0% {
    opacity: 0;
    filter: brightness(3.5) blur(10px);
  }
  10% {
    opacity: 1;
    filter: brightness(3) blur(6px);
  }
  16% {
    opacity: 0.25;
    filter: brightness(0.9) blur(2px);
  }
  24% {
    opacity: 1;
    filter: brightness(2.2) blur(3px);
  }
  36% {
    opacity: 0.7;
    filter: brightness(1.05) blur(0.5px);
  }
  52% {
    opacity: 1;
    filter: brightness(1.7) blur(1.2px);
  }
  100% {
    opacity: 1;
    filter: brightness(1) blur(0);
  }
}

/* One horizontal stumble per cycle, ~19ms per segment at 12.4s */
@keyframes ps-jitter {
  0%,
  99.4%,
  100% {
    transform: translateX(0);
  }
  99.55% {
    transform: translateX(3px) skewX(-0.6deg);
  }
  99.7% {
    transform: translateX(-2px);
  }
  99.85% {
    transform: translateX(1px);
  }
}

/* Two brief brightness breaths per 9.4s cycle */
@keyframes ps-flicker {
  0%,
  31.2%,
  32.1%,
  67.3%,
  67.8%,
  100% {
    opacity: 0.8;
  }
  31.4% {
    opacity: 1;
  }
  31.8% {
    opacity: 0.6;
  }
  67.5% {
    opacity: 0.95;
  }
}

/* ==========================================================================
   Reduced motion — instant everything, one beautiful static frame
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .ps-js .ps-crt,
  .ps-js .ps-crt__glare,
  .ps-js .ps-cursor,
  .ps-js .ps-hero__id.is-on .ps-title__text,
  .ps-js .ps-hero__id.is-on .ps-hero__sub,
  .ps-js .ps-hero__id.is-on .ps-hero__meta,
  .ps-js .ps-dish__note.is-open p {
    animation: none;
  }

  .ps-js .ps-hero__id.is-waiting {
    opacity: 1;
  }

  .ps-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }
}
